const item = $input.first().json;

// 1. Extraemos el contenido string directamente
const contentString = item.body?.content || '';

// 2. Limpiamos las etiquetas HTML para dejar solo el comando (ej: "/query 51748")
const raw = contentString.replace(/<at>.*?<\/at>/g, '').replace(/<[^>]+>/g, '').trim();

// 3. Match del comando
const m = raw.match(/^\/(\w+)\s*(.*)$/);

// Si el mensaje no tiene el formato de comando (no empieza con "/"), devolvemos objeto vacío
if (!m) {
  return []; 
  // Nota: Si querías detener el flujo por completo, usa: return [];
}

// 4. Extraemos el channelId desde el @odata.context usando la regex probada
let channelId = '';
const contextUrl = item['@odata.context'] || '';
const channelMatch = contextUrl.match(/channels\('([^']+)'\)/);

if (channelMatch && channelMatch[1]) {
    // 5. Clave: Decodificar el string para transformar %3A en : y %40 en @
    channelId = decodeURIComponent(channelMatch[1]);
}

// 6. Diccionario de países
const canalPais = {
  '19:NohjVulNVM9XkmN1lG0Y4aRWueYhTX1eLWX66T-n83Y1@thread.tacv2': 'CO',
  '19:NQRQiHrUhszmot2VXKYb_bU_YEOJCW1DGq5vKLpnTpw1@thread.tacv2': 'AR' 
};

// 7. Retorno exitoso
return [{ 
  json: {
    comando: m[1].toLowerCase(),
    arg: m[2].trim(),
    channelId: channelId,
    pais_canal: canalPais[channelId] || null
  }
}];

const rows = $input.all().map(i => i.json);
const scope = $('Parse Command').first().json.arg || $('Parse Command').first().json.pais_canal || 'TODOS';
if (!rows.length) return [{ json: { reply: `No hay queries para ${scope}.` } }];
const grupos = {};
for (const r of rows) (grupos[r.type || 'sin-type'] ||= []).push(r.query_id);
let txt = `**Queries (${scope})**\n`;
for (const [t, ids] of Object.entries(grupos)) txt += `\n**${t} (${ids.length}):** ${ids.join(', ')}`;
return [{ json: { reply: txt } }];

const rows = $input.all().map(i => i.json).filter(j => j.query_id);
const id = $('Parse Command').first().json.arg;
if (!rows.length) return [{ json: { reply: `No encontré la query ${id}.` } }];
let txt = '';
rows.forEach((r, i) => {
  const tag = rows.length > 1 ? ` (variante ${i+1}/${rows.length})` : '';
  // Se reemplaza el bloque de markdown por etiquetas HTML <code>
  txt += `**${r.query_id}${tag}** — ${r.description || ''}\n\n<code>\n${r.revision_query}\n</code>\n\n`;
});
return [{ json: { reply: txt.trim() } }];

const id = $json.arg;
if (!id) return [{ json: { reply: 'Uso: /docs [id]' } }];
const url = `https://apg.cloudafm.com:443/default.aspx?accion=editardoc&DocumentoId=${id}&VersionId=1`;
return [{ json: { reply: `<a href="${url}">Link al AFM</a>` } }];

const q = $json;
if (!q.query_id) return [{ json: { reply: `No encontré la query ${$('Retry Split').first().json.retry_id}.`, _skip: true } }];
const app = (q.application || '').trim();
const flag = app === 'COMFIAR 2' ? 'comfiar2' : (app === 'VIGA' || app === 'Beelling') ? 'apgcore' : 'COMFIAR';
return [{ json: { ...q,
  flag,
  country: $('Parse Command').first().json.pais_canal,
  entorno: $('Retry Split').first().json.retry_entorno,
  hora_ejecucion_real: DateTime.now().setZone('America/Argentina/Buenos_Aires').toFormat("yyyy-MM-dd'T'HH:mm:ss.SSS"),
  audit_startTime: new Date().getTime()
}}];

