const err = r.find(x => typeof x.error === 'string');
if (err) return [{ json: { reply: `❌ Retry ${id} ${ent}: ${err.error}` } }];
const filas = r.filter(x => x && Object.keys(x).length > 0).length;
return [{ json: { reply: `✅ Retry ${id} ${ent}: ${filas} fila(s).` } }];

